const SENSOR_CLUSTERS = new Set([1029, 1024, 1030, 1026]);
const NODE_ID = 2;

let d;
try {
    const raw = msg.payload;
    if (!raw) return null;
    d = (typeof raw === 'object') ? raw : JSON.parse(raw);
} catch(e) { return null; }
if (!d || typeof d !== 'object') return null;

if (d.fabric_id !== undefined) {
    node.status({fill:'yellow', shape:'ring', text:'Connecting…'});
    return [null, {
        payload: JSON.stringify({
            message_id: 'listen-2',
            command:    'start_listening',
            args:       {}
        })
    }];
}

if (d.message_id === 'listen-2' && Array.isArray(d.result)) {
    const node1 = d.result.find(n => n.node_id === NODE_ID);
    if (!node1) return null;
    const flat = [];
    Object.keys(node1.attributes || {}).forEach(path => {
        const parts     = String(path).split('/');
        const clusterId = parseInt(parts[1], 10);
        const attrId    = parseInt(parts[2], 10);
        const value     = node1.attributes[path];
        if (SENSOR_CLUSTERS.has(clusterId) && attrId === 0
                && value !== null && value !== undefined) {
            flat.push({ payload: { clusterId, value } });
        }
    });
    if (flat.length) {
        node.status({fill:'green', shape:'dot', text:'Live'});
        return [flat, null];
    }
    return null;
}

if (d.event === 'attribute_updated' && Array.isArray(d.data)) {
    const [nodeId, path, value] = d.data;
    if (nodeId !== NODE_ID) return null;
    const parts     = String(path).split('/');
    const clusterId = parseInt(parts[1], 10);
    if (isNaN(clusterId) || !SENSOR_CLUSTERS.has(clusterId)) return null;
    return [{ payload: { clusterId, value } }, null];
}

return null;

const p = msg.payload;
if (!p || p.clusterId === undefined) return [null,null,null,null];
const id  = p.clusterId;
const val = p.value;
if (id === 1029) return [{ payload: parseFloat((val/100).toFixed(2)), topic:'humidity'    }, null, null, null];
if (id === 1024) return [null, { payload: val > 1 ? Math.round(Math.pow(10,(val-1)/10000)) : 0, topic:'illuminance' }, null, null];
if (id === 1030) return [null, null, { payload: (val & 1) ? 'Detected':'Clear', topic:'occupancy'  }, null];
if (id === 1026) return [null, null, null, { payload: parseFloat((val/100).toFixed(1)), topic:'temperature' }];
return [null,null,null,null];

const v = msg.payload;
if (v == null) { node.status({fill:'grey',shape:'ring',text:'—'}); return null; }
node.status({fill:'blue', shape:'dot', text: v + ' %'});
return msg;

const v = msg.payload;
if (v == null) { node.status({fill:'grey',shape:'ring',text:'—'}); return null; }
node.status({fill:'yellow', shape:'dot', text: v + ' lx'});
return msg;

const v = msg.payload;
if (v == null) { node.status({fill:'grey',shape:'ring',text:'—'}); return null; }
const det = (v === 'Detected');
node.status({fill:det?'green':'grey', shape:det?'dot':'ring', text:v});
return msg;

const v = msg.payload;
if (v == null) { node.status({fill:'grey',shape:'ring',text:'—'}); return null; }
node.status({fill:'red', shape:'dot', text: v + ' °C'});
return msg;

const occupied = (msg.payload === 'Detected');
const timeStr  = new Date().toLocaleTimeString('en-GB',{hour12:false});
if (occupied) {
    context.set('detectedAt', timeStr);
    node.status({fill:'green',shape:'dot',text:'💡 ON — detected at '+timeStr});
    msg.payload = 'ON';
} else {
    const since = context.get('detectedAt') || '—';
    node.status({fill:'grey',shape:'ring',text:'💡 OFF — cleared at '+timeStr+' (on since '+since+')'});
    msg.payload = 'OFF';
}
return msg;
